#include <iostream>
#include <string>

using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    string s;
    getline(cin, s);

    int balance = 0;
    for (char ch : s) {
        if (ch == '(') {
            balance++;
        } else if (ch == ')') {
            balance--;
            if (balance < 0) {
                cout << "Bad\n";
                return 0;
            }
        }
    }

    if (balance == 0) {
        cout << "Good\n";
    } else {
        cout << "Bad\n";
    }

    return 0;
}
